function Recommendations({ places }) {

  return (

    <div className="card">

      <h2>
        Recommended Places
      </h2>

      {places.map((place, index) => (

        <div
          key={index}
          className="item"
        >

          <h3>
            {place.name}
          </h3>

          <p>
            Type: {place.type}
          </p>

          <p>
            City: {place.city}
          </p>

          <p>
            State: {place.state}
          </p>

          <p>
            Budget: ₹{place.budget}
          </p>

        </div>
      ))}

    </div>
  );
}

export default Recommendations;
